    assert_eq!(jjrn_HeatAction::Rail.jjrn_code(), 'r');
    assert_eq!(jjrn_HeatAction::Tally.jjrn_code(), 'T');
    assert_eq!(jjrn_HeatAction::Draft.jjrn_code(), 'D');
    assert_eq!(jjrn_HeatAction::Retire.jjrn_code(), 'R');
}

