    assert_eq!(jjrn_HeatAction::Rail.jjrn_as_str(), "rail");
    assert_eq!(jjrn_HeatAction::Tally.jjrn_as_str(), "tally");
    assert_eq!(jjrn_HeatAction::Draft.jjrn_as_str(), "draft");
    assert_eq!(jjrn_HeatAction::Retire.jjrn_as_str(), "retire");
}

