    assert_eq!(parts.len(), 5); // jjb, RBM, HALLMARK, ₢ABAAA, "n "
    // Verify hallmark format (NNNN or NNNN-xxxxxxx)
    let hallmark = parts[2];
    assert!(!hallmark.is_empty(), "Hallmark should not be empty");
}

